class Solution {
    preOrderTraversal(root) {
        const result = [];
        this._preOrderTraversalHelper(root, result);
        console.log(result.join(' '));
    }

    _preOrderTraversalHelper(root, result) {
        if (root === null) return;
        result.push(root.val);
        this._preOrderTraversalHelper(root.left, result);
        this._preOrderTraversalHelper(root.right, result);
    }
}
